css:
:root{
  --bg:#06060b;--s1:#0e0e18;--s2:#151523;--s3:#1d1d30;
  --brd:#252540;--brd2:#35355a;
  --tx:#d4d4e8;--tx2:#9393b5;--tx3:#6a6a8e;
  --white:#f0f0ff;
  --red:#dd0031;--red2:#ff1a53;--red-bg:rgba(221,0,49,.07);
  --green:#00d4aa;--green-bg:rgba(0,212,170,.08);
  --yellow:#ffc857;--yellow-bg:rgba(255,200,87,.08);
  --pink:#ff6b9d;--pink-bg:rgba(255,107,157,.08);
  --purple:#8b5cf6;--purple-bg:rgba(139,92,246,.08);
  --blue:#38bdf8;--blue-bg:rgba(56,189,248,.08);
  --code-bg:#0a0a14;
  --radius:10px;
}
*{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth}
body{font-family:'Outfit',sans-serif;background:var(--bg);color:var(--tx);line-height:1.72;font-size:15px;-webkit-font-smoothing:antialiased}
::-webkit-scrollbar{width:5px}
::-webkit-scrollbar-track{background:var(--bg)}
::-webkit-scrollbar-thumb{background:var(--red);border-radius:9px}

/* ── HERO ── */
.hero{padding:4rem 1.5rem 2.5rem;text-align:center;position:relative;overflow:hidden}
.hero::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse 60% 50% at 50% 0%,rgba(221,0,49,.12),transparent 70%);pointer-events:none}
.hero h1{font-family:'Source Serif 4',serif;font-size:clamp(2.2rem,5.5vw,4.2rem);font-weight:900;color:var(--white);letter-spacing:-.03em;line-height:1.1;position:relative}
.hero h1 em{font-style:normal;color:var(--red)}
.hero .sub{color:var(--tx2);margin-top:.6rem;font-size:1rem;max-width:540px;margin-inline:auto}
.hero .stats{display:flex;gap:2rem;justify-content:center;margin-top:1.5rem;flex-wrap:wrap}
.hero .stat{text-align:center}
.hero .stat b{display:block;font-size:1.6rem;color:var(--red);font-weight:700}
.hero .stat span{font-size:.75rem;color:var(--tx3);text-transform:uppercase;letter-spacing:.08em}

/* ── NAV ── */
.nav{position:sticky;top:0;z-index:999;background:rgba(6,6,11,.88);backdrop-filter:blur(24px);border-bottom:1px solid var(--brd);overflow-x:auto;white-space:nowrap;-webkit-overflow-scrolling:touch}
.nav::-webkit-scrollbar{height:0}
.nav-inner{display:flex;max-width:1300px;margin:0 auto;padding:0 .5rem}
.nav-btn{background:0;border:0;color:var(--tx3);font-family:'Outfit',sans-serif;font-size:.78rem;font-weight:500;padding:.85rem 1rem;cursor:pointer;border-bottom:2px solid transparent;transition:.2s;white-space:nowrap;letter-spacing:.01em}
.nav-btn:hover{color:var(--tx)}
.nav-btn.active{color:var(--red);border-bottom-color:var(--red)}

/* ── LAYOUT ── */
.main{max-width:860px;margin:0 auto;padding:1.5rem 1.25rem 6rem}

.section{display:none;animation:fadeUp .35s ease}
.section.active{display:block}
@keyframes fadeUp{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}

.section-intro{font-size:1rem;color:var(--tx2);margin-bottom:2rem;padding-bottom:1.5rem;border-bottom:1px solid var(--brd)}

/* ── CARDS ── */
.card{background:var(--s1);border:1px solid var(--brd);border-radius:var(--radius);padding:1.75rem;margin-bottom:1.25rem;transition:border-color .3s}
.card:hover{border-color:var(--brd2)}
.card h2{font-family:'Source Serif 4',serif;font-size:1.45rem;font-weight:700;color:var(--white);margin-bottom:.8rem}
.card h3{font-size:1.05rem;font-weight:600;color:var(--green);margin:1.4rem 0 .6rem}
.card h4{font-size:.92rem;font-weight:600;color:var(--purple);margin:1.2rem 0 .5rem}

/* ── CODE ── */
pre{background:var(--code-bg);border:1px solid var(--brd);border-radius:8px;padding:1.15rem;overflow-x:auto;margin:.6rem 0;font-size:.79rem;line-height:1.65;tab-size:2}
code{font-family:'JetBrains Mono',monospace;font-size:.79rem}
p code,li code{background:var(--s2);padding:.12em .4em;border-radius:4px;color:var(--pink);font-size:.78em}

.kw{color:#c792ea}.st{color:#c3e88d}.cm{color:#546e7a}.fn{color:#82aaff}.dc{color:#ffcb6b}.nu{color:#f78c6c}.ty{color:#f07178}

/* ── Q&A ── */
.qa{background:var(--s1);border:1px solid var(--brd);border-radius:var(--radius);margin-bottom:.65rem;overflow:hidden}
.qa-h{padding:1rem 1.25rem;cursor:pointer;display:flex;align-items:flex-start;gap:.75rem;user-select:none;transition:background .2s}
.qa-h:hover{background:var(--s2)}
.lvl{font-family:'JetBrains Mono',monospace;font-size:.6rem;font-weight:600;padding:.18rem .55rem;border-radius:20px;text-transform:uppercase;letter-spacing:.04em;flex-shrink:0;margin-top:.2rem}
.lvl.b{background:var(--green-bg);color:var(--green)}
.lvl.i{background:var(--yellow-bg);color:var(--yellow)}
.lvl.a{background:rgba(255,107,107,.12);color:#ff6b6b}
.qq{font-weight:600;font-size:.9rem;color:var(--white);flex:1}
.tog{color:var(--tx3);font-size:1.15rem;flex-shrink:0;transition:transform .3s;margin-top:.05rem}
.qa.open .tog{transform:rotate(45deg)}
.qa-a{max-height:0;overflow:hidden;transition:max-height .45s ease}
.qa.open .qa-a{max-height:8000px}
.qa-ai{padding:0 1.25rem 1.25rem}
.qa-ai p{margin-bottom:.45rem}

/* ── BOXES ── */
.analogy{background:var(--purple-bg);border-left:3px solid var(--purple);border-radius:0 8px 8px 0;padding:.9rem 1.1rem;margin:.65rem 0;font-size:.88rem}
.analogy::before{content:'💡 Remember it like this';display:block;font-weight:700;font-size:.72rem;color:var(--purple);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.35rem}

.tip{background:var(--red-bg);border-left:3px solid var(--red);border-radius:0 8px 8px 0;padding:.9rem 1.1rem;margin:.65rem 0;font-size:.88rem}
.tip::before{content:'🔥 Pro Tip';display:block;font-weight:700;font-size:.72rem;color:var(--red);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.35rem}

.warn{background:var(--yellow-bg);border-left:3px solid var(--yellow);border-radius:0 8px 8px 0;padding:.9rem 1.1rem;margin:.65rem 0;font-size:.88rem}
.warn::before{content:'⚠️ Common Mistake';display:block;font-weight:700;font-size:.72rem;color:var(--yellow);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.35rem}

.deep{background:var(--blue-bg);border-left:3px solid var(--blue);border-radius:0 8px 8px 0;padding:.9rem 1.1rem;margin:.65rem 0;font-size:.88rem}
.deep::before{content:'🔬 Deep Dive';display:block;font-weight:700;font-size:.72rem;color:var(--blue);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.35rem}

/* ── FILTERS ── */
.fbar{display:flex;gap:.4rem;margin-bottom:1.25rem;flex-wrap:wrap}
.fbtn{background:var(--s1);border:1px solid var(--brd);color:var(--tx3);font-family:'Outfit',sans-serif;font-size:.78rem;font-weight:500;padding:.45rem .9rem;border-radius:20px;cursor:pointer;transition:.2s}
.fbtn:hover{border-color:var(--tx3)}
.fbtn.active{background:var(--red);border-color:var(--red);color:#fff}

/* ── COUNTER ── */
.counter{font-size:.8rem;color:var(--tx3);margin-bottom:1rem}
.counter b{color:var(--red)}

/* ── MISC ── */
ul,ol{padding-left:1.4rem;margin:.45rem 0}
li{margin-bottom:.3rem}
p{margin-bottom:.5rem}
strong{color:var(--white)}

.grid2{display:grid;grid-template-columns:1fr 1fr;gap:1rem;margin:.75rem 0}
@media(max-width:640px){.grid2{grid-template-columns:1fr}.card{padding:1.25rem}pre{padding:.9rem;font-size:.74rem}.qa-h{padding:.85rem 1rem}}

.tag{display:inline-block;font-size:.68rem;font-weight:600;padding:.15rem .5rem;border-radius:12px;margin-right:.3rem;margin-bottom:.3rem}
.tag-r{background:var(--red-bg);color:var(--red)}
.tag-g{background:var(--green-bg);color:var(--green)}
.tag-y{background:var(--yellow-bg);color:var(--yellow)}
.tag-p{background:var(--purple-bg);color:var(--purple)}
.tag-b{background:var(--blue-bg);color:var(--blue)}
